import { NextResponse } from "next/server";
import nodemailer from "nodemailer";

export async function POST(req: Request) {
    try {
        const { email } = await req.json();

        const transporter = nodemailer.createTransport({
        service: "gmail",
        auth: {
            user: process.env.EMAIL_USER, // standhric2024@gmail.com
            pass: process.env.EMAIL_PASS, // 16 digit kode dari gambar tadi
        },
        });

        const resetUrl = `http://localhost:3000/reset-password?email=${email}`;

        await transporter.sendMail({
        from: '"ET-Pareto" <noreply@etpareto.com>',
        to: email,
        subject: "Reset Password Akun ET-Pareto",
        html: `
            <div style="font-family: sans-serif; padding: 20px;">
            <h2>Halo, Stan!</h2>
            <p>Kamu meminta reset password. Klik tombol di bawah untuk lanjut:</p>
            <a href="${resetUrl}" style="background: #2563eb; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">Reset Password</a>
            <p style="margin-top: 20px; font-size: 12px; color: gray;">Kalau kamu nggak merasa minta ini, abaikan saja ya.</p>
            </div>
        `,
        });

        return NextResponse.json({ message: "Email terkirim!" });
    } catch (error) {
        console.log(error);
        return NextResponse.json({ error: "Gagal kirim email" }, { status: 500 });
    }
}